// Solution
function calculateColumnWidths(items) {
  let totalWidth = 800;
  let totalItems = items.reduce((a, b) => a + b, 0);
  let columnWidths = new Array(items.length);
  for (let i = 0; i < items.length; i++) {
    columnWidths[i] = totalWidth / totalItems * items[i];
  }
  return columnWidths;
}

